<!-- OR422 -->
%@LW_pgstart@@
<html>
<head>
    <title>%@LW_PField_s_prnFile@%</title>
    <style>
        body {
            background-color: #fff;
            font-family: sans-serif;
            /**padding-bottom: 20px;**/
            padding-left: 30px;
            padding-top: 40px;
            padding-right: 40px;
            width: 1500px;
            height:850px;
        }
        th{
            color:000;
            height: 10px;
            white-space: nowrap;
        }
        th,td {
            padding: 0 0 0 5px;
        }
        .isi tr:nth-child(even){
            background-color : #d4d0ff;
        }
        .customers tr:hover{
            background-color : #ddd;
        }
        table {
            border-collapse:collapse;
            font-size:12px;
             width: 38cm; 
        }
        .isi table, .isi td, .isi th {
            border:1px solid black;
        }
        .gtot{
            border-top: 1px solid #000;
            border-bottom: 1px solid #000;
            font-weight: bold;
        }
        .ltot,.gtot{
            background-color: #ededed;
            font-weight: bold !important;
        }
        hr{
            display: block;
            height: 1px;
            background: transparent;
            width: 100%;
            border: none;
            border-top: solid 1px #000;
            margin-top: 0px;
            margin-bottom: 0px;
        }
        #head  table, #head td, #head th{
            border:none !important;
        }
        @media print {
            .no-print, .no-print *
            {
                display: none !important;
            }
            @page{
                margin: 4mm 4mm 4mm 4mm;
            }
            .ltot,.gtot{
                background-color: #ededed;
            }
            table { page-break-after:always!important; }
            table tr    { page-break-after:always!important; }
            table td    { page-break-after:always!important; }
            table thead { display:table-header-group!important }
            table tfoot { display:table-footer-group!important }
            .padding th { padding-top: 5mm!important }
        }
    </style>
</head>
<script src="https://code.jquery.com/jquery-1.12.4.js"></script>
<script src="https://code.jquery.com/ui/1.12.1/jquery-ui.js"></script>
<script type="text/javascript">
    var kmGtot = 0.0;
    function sanitizeString(string){
      if ((string + '').includes(','))
        string = string.replace(/,/g, '')
      return (isNaN(string = parseFloat(string))) ? 0 : string
    }
</script>
</head>
<body bgcolor="#ffffff" text="#000" style="font-family:arial;">
    LW_pgstart@%
    %@LW_vars@prn_pglen=55;prn_yLine=10;
    LW_vars@%
    %@LW_prowno_0@@
    <button class="no-print" onclick="window.print()">Print</button>
    <table>
        <thead style="white-space: nowrap; padding-left: 5px;">
            <tr class="padding">
                <th colspan="15" style="font-size:20px" align="left"><b>%@LW_PField_Pub_Company@%</b></th>
                <th align="right">%@LW_PField_today() + ' *' + ProgNo + '*'@%</th>
            </tr>
            <tr height="50px" valign="top">
                <th colspan="16" align="center" style="font-size: 1.5em; font-weight: bold;">Time Record per Employee Report</th>
            </tr>
            <tr>
                <th align="left">Date</th>
                <th align="left" colspan="12">: %@LW_PField_s_dt_f@D,D@% - %@LW_PField_s_dt_t@D,D@%</th>
            </tr>
            <tr>
                <th align="left">Emp. No.</th>
                <th align="left" colspan="12">: %@LW_PField_s_emp_f@% - %@LW_PField_s_emp_t@%</th>
            </tr>
            <tr>
                <th valign="bottom" colspan="16"><hr align="left" style="margin-top:0px; margin-bottom:0px"></th>
            </tr>
            <tr>
                <th align="left" valign="top">seq</th> <!-- 1 -->
                <th align="left" valign="top">Empno</th> <!-- 2 -->
                <th align="left" valign="top">Emp. Name</th> <!-- 3 -->
                <th align="left" valign="top">Date</th> <!-- 4 -->
                <th align="left" valign="top">Addition date</th> <!-- 4 -->
                <th align="right" valign="top">Time</th> <!-- 5 -->
                <th align="right" valign="top">Start</th> <!-- 6 -->
                <th align="right" valign="top">End</th> <!-- 7 -->
                <th align="right" valign="top">End2</th> <!-- 8 -->
                <th align="right" valign="top">Expense</th> <!-- 9 -->
                <!-- <th align="left" valign="top">v</th> --> <!-- 10 -->
                <th align="right" valign="top">Trv. to</th> <!-- 11 -->
                <th align="right" valign="top">Trv. Back</th> <!-- 12 -->
                <th align="right" valign="top">W. Hour</th> <!-- 13 -->
                <th align="right" valign="top">KM</th> <!-- 14 -->
                <th align="left" valign="top">Job Cd.</th> <!-- 15 -->
                <!-- <th align="right" valign="top">hmm</th> --> <!-- 16 -->
                <th align="left" valign="top">Description</th> <!-- 17 --> 
            </tr>
            <tr>
                <th valign="bottom" colspan="16"><hr align="left" style="margin-top:0px; margin-bottom:0px"></th>
            </tr>
        </thead>
        LW_prowno_0@%

        <tbody>
            %@LW_prowno_10@@
            <tr>
                <td align="left" valign="top">%@LW_PField_tr_seqno@%</td> <!-- 1 -->
                <td align="left" valign="top">%@LW_PField_tr_empno@%</td> <!-- 2 -->
                <td align="left" valign="top">%@LW_PField_TableDS(pr010a, "em_name", tr_empno)@%</td> <!-- 3 -->
                <td align="left" valign="top">%@LW_PField_tr_date@D,D@%</td> <!-- 4 -->
                <td align="left" valign="top">%@LW_PField_tr_hwdateA@D,D@%</td> <!-- 4 -->
                <td align="right" valign="top">%@LW_PField_tr_time@%</td> <!-- 5 -->
                <td align="right" valign="top">%@LW_PField_tr_timeStart@%</td> <!-- 6 -->
                <td align="right" valign="top">%@LW_PField_tr_timeEnd@%</td> <!-- 7 -->
                <td align="right" valign="top">%@LW_PField_tr_timeEnd2@%</td> <!-- 8 -->
                <td align="right" valign="top">%@LW_PField_tr_expense@%</td> <!-- 9 -->
                <!-- <td align="left" valign="top">%@LW_PField_tr_visit@%</td> --> <!-- 10 -->
                <td align="right" valign="top">%@LW_PField_tr_timestart-tr_time@%</td> <!-- 11 -->
                <td align="right" valign="top">%@LW_PField_tr_timeEnd2-tr_timeEnd@%</td> <!-- 12 -->
                <td align="right" valign="top">%@LW_PField_tr_timeEnd-tr_time@N/2,N,10,1@%</td> <!-- 13 -->
                <td align="right" valign="top">%@LW_PField_htm_kmEnd - htm_kmStart@N/2,N,20,1@%</td> <!-- 14 -->
                <td align="left" valign="top">%@LW_PField_TableDS(or800a, "tb_descr", tr_jobcd)@%</td> <!-- 15 -->
                <!-- <td align="right" valign="top"></td> --> <!-- 16 -->
                <td align="left" valign="top">%@LW_PField_tr_descr@%</td> <!-- 17 -->
            </tr>

            %@colom@ !empty(tr_descr2) .or. !empty(tr_jobCd2)@
            <tr>
                <td align="left" valign="top" valign="top" colspan="13"></td>
                <td align="right" valign="top" valign="top">%@LW_PField_htm_kmEnd2 - htm_kmStart2@N/2,N,20,1@%</td> <!-- 14 -->
                <td align="left" valign="top">%@LW_PField_TableDS(or800a, "tb_descr", tr_jobcd2)@%</td>
                <!-- <td align="right" valign="top">%@LW_PField_tr_prgno2@%</td> --> <!-- 16 -->
                <td align="left" valign="top">%@LW_PField_tr_descr2@%</td>
            </tr>
            colom@%

            %@colom@ !empty(tr_descr3) .or. !empty(tr_jobCd3)@
            <tr>
                <td align="left" valign="top" valign="top" colspan="13"></td>
                <td align="right" valign="top" valign="top">%@LW_PField_htm_kmEnd3 - htm_kmStart3@N/2,N,20,1@%</td> <!-- 14 -->
                <td align="left" valign="top">%@LW_PField_TableDS(or800a, "tb_descr", tr_jobcd3)@%</td>
                <!-- <td align="right" valign="top">%@LW_PField_tr_prgno3@%</td> --> <!-- 16 -->
                <td align="left" valign="top">%@LW_PField_tr_descr3@%</td>
            </tr>
            colom@%

            %@colom@ !empty(tr_descr4) .or. !empty(tr_jobCd4)@
            <tr>
                <td align="left" valign="top" valign="top" colspan="13"></td>
                <td align="right" valign="top" valign="top">%@LW_PField_htm_kmEnd4 - htm_kmStart4@N/2,N,20,1@%</td> <!-- 14 -->
                <td align="left" valign="top">%@LW_PField_TableDS(or800a, "tb_descr", tr_jobcd4)@%</td>
                <!-- <td align="right" valign="top">%@LW_PField_tr_prgno4@%</td> --> <!-- 16 -->
                <td align="left" valign="top">%@LW_PField_tr_descr4@%</td>
            </tr>
            colom@%

            %@colom@ !empty(tr_descr5) .or. !empty(tr_jobCd5)@
            <tr>
                <td align="left" valign="top" valign="top" colspan="13"></td>
                <td align="right" valign="top" valign="top">%@LW_PField_htm_kmEnd5 - htm_kmStart5@N/2,N,20,1@%</td> <!-- 14 -->
                <td align="left" valign="top">%@LW_PField_TableDS(or800a, "tb_descr", tr_jobcd5)@%</td>
                <!-- <td align="right" valign="top">%@LW_PField_tr_prgno5@%</td> --> <!-- 16 -->
                <td align="left" valign="top">%@LW_PField_tr_descr5@%</td>
            </tr>
            colom@%

            %@LW_PRow_add@1@%
            LW_prowno_10@%

            %@LW_prowno_119@@
            <tr class="ltot">
                <td colspan="12" valign="top">&nbsp;</td>
                <td align="right" valign="top">%@LW_PField__Ltot_10@N/2,N@%</td>
                <td align="right" valign="top">%@LW_PField__Ltot_20@N/2,N@%</td>
                <script type="text/javascript">
                    kmGtot += sanitizeString("%@LW_PField__Ltot_20@N/2,N@%");
                </script>
                <td colspan="3"></td>
            </tr>
            %@LW_PRow_add@1@%
            LW_prowno_119@%

            %@LW_prowno_999@@
            <tr class="gtot">
                <td align="right" colspan="12" valign="top">Grand total</td>
                <td align="right" valign="top">%@LW_PField__Gtot_10@N/2,N@%</td>
<!--                 <td align="right" valign="top">
                    <script type="text/javascript">document.write(kmGtot)</script>
                </td> -->
                <!-- <td align="right" valign="top">%@LW_PField__Gtot_20@N/2,N@%</td> -->
                <td colspan="3"></td>
            </tr>
        </tbody>
<!--         LW_prowno_999@% -->
    </table>
</body>
%@LW_pgend@@
LW_pgend@%
</html>
